create table payment_history (amount numeric(38,2), amount_in_base_currency numeric(38,2), exchange_rate_at_payment numeric(38,2), id integer generated by default as identity, payment_date date, subscription_id integer not null, created_at timestamp(6), created_date timestamp(6), updated_at timestamp(6), currency varchar(255) check (currency in ('UZS','USD','EUR','RUB')), primary key (id));
create table refresh_token (id integer generated by default as identity, revoked boolean not null, user_id integer, created_at timestamp(6), expiry_date timestamp(6) not null, updated_at timestamp(6), token varchar(255) not null unique, primary key (id));
create table subscription (amount numeric(38,2), id integer generated by default as identity, is_delete boolean, set_next_payment_date date, start_date date, user_id integer, created_at timestamp(6), updated_at timestamp(6), billing_cycle varchar(255) check (billing_cycle in ('WEEKLY','MONTHLY','YEARLY')), currency varchar(255) check (currency in ('UZS','USD','EUR','RUB')), service_name varchar(255), status varchar(255) check (status in ('ACTIVE','PAUSED','CANCELLED')), subscription_category varchar(255) check (subscription_category in ('ENTERTAINMENT','PRODUCTIVITY','AI_TOOLS','EDUCATION','HEALTH_FITNESS','CLOUD_STORAGE','OTHER')), primary key (id));
create table users (account_non_locked boolean not null, email_code integer, enabled boolean not null, id integer generated by default as identity, notification_enabled boolean not null, created_at timestamp(6), updated_at timestamp(6), email varchar(255) not null unique, full_name varchar(255), password varchar(255) not null, preferred_currency varchar(255) check (preferred_currency in ('UZS','USD','EUR','RUB')), role varchar(255) check (role in ('USER','ADMIN')), username varchar(255) not null unique, primary key (id));
alter table if exists payment_history add constraint FK61846vqoaitb3b78lw3g7h3uo foreign key (subscription_id) references subscription;
alter table if exists refresh_token add constraint FKjtx87i0jvq2svedphegvdwcuy foreign key (user_id) references users;
alter table if exists subscription add constraint FKqwd9pkhbsmapx9poug5wnnpkc foreign key (user_id) references users;
